#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Structure to represent a graph
typedef struct {
    int V;
    int **adj;
} Graph;

// Function to create a graph
Graph* createGraph(int V) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;
    graph->adj = (int**) malloc(V * sizeof(int*));
    for (int i = 0; i < V; i++) {
        graph->adj[i] = (int*) malloc(V * sizeof(int));
        for (int j = 0; j < V; j++) {
            graph->adj[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adj[u][v] = 1;
    graph->adj[v][u] = 1;
}

// Function to perform BFS
void bfs(Graph* graph, int s, bool* visited) {
    int* queue = (int*) malloc(graph->V * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = s;
    visited[s] = true;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < graph->V; v++) {
            if (graph->adj[u][v] && !visited[v]) {
                queue[rear++] = v;
                visited[v] = true;
            }
        }
    }
    free(queue);
}

// Function to count connected components
int countComponents(Graph* graph) {
    bool* visited = (bool*) malloc(graph->V * sizeof(bool));
    for (int i = 0; i < graph->V; i++) {
        visited[i] = false;
    }
    int count = 0;
    for (int i = 0; i < graph->V; i++) {
        if (!visited[i]) {
            bfs(graph, i, visited);
            count++;
        }
    }
    free(visited);
    return count;
}

int main() {
    int V = 5;
    Graph* graph = createGraph(V);
    addEdge(graph, 0, 1);
    addEdge(graph, 1, 2);
    addEdge(graph, 3, 4);
    printf("Number of Connected Components: %d\n", countComponents(graph));
    return 0;
}

